mapper.select:
select count(*)
from workflow_transition wt
join issue_type it
on
wt.issue_type_id = it.issue_type_id
join role r
on wt.role_id =
r.role_id
join issue_status fs
on wt.from_status_id = fs.issue_status_id
join issue_status ts
on wt.to_status_id = ts.issue_status_id
where
wt.issue_type_id = #{sourceIssueTypeId}
and wt.role_id =
#{sourceRoleId}
and wt.apply_target_code in

	#{applyTargetCode}

and it.user_id = #{userId}
and r.created_by = #{userId}
and fs.user_id =
#{userId}
and ts.user_id = #{userId}

mapper.delete:
delete from workflow_transition
where issue_type_id in (
select
issue_type_id
from issue_type
where issue_type_id = #{targetIssueTypeId}
and user_id = #{userId}
)
and role_id in (
select role_id
from role
where
role_id = #{targetRoleId}
and created_by = #{userId}
)
and
apply_target_code in

	#{applyTargetCode}

mapper.insert:
insert into workflow_transition ( transition_id, issue_type_id, role_id, from_status_id, to_status_id, apply_target_code, created_by, created_at ) select 'WORKFLOW_TRANSITION_' || to_char(sysdate, 'YYMM') || '_' || lpad( ( select nvl(max(to_number(substr(transition_id, -4))), 0) from workflow_transition where substr(transition_id, 1, 25) = 'WORKFLOW_TRANSITION_' || to_char(sysdate, 'YYMM') || '_' ) + row_number() over (order by wt.apply_target_code, wt.transition_id), 4, '0' ) as transition_id, #{targetIssueTypeId}, #{targetRoleId}, wt.from_status_id, wt.to_status_id, wt.apply_target_code, #{createdBy}, sysdate from workflow_transition wt join issue_type source_it on wt.issue_type_id = source_it.issue_type_id join role source_role on wt.role_id = source_role.role_id join issue_type target_it on target_it.issue_type_id = #{targetIssueTypeId} join role target_role on target_role.role_id = #{targetRoleId} join issue_status fs on wt.from_status_id = fs.issue_status_id join issue_status ts on wt.to_status_id = ts.issue_status_id where wt.issue_type_id = #{sourceIssueTypeId} and wt.role_id = #{sourceRoleId} and wt.apply_target_code in
#{applyTargetCode}
and source_it.user_id = #{userId} and target_it.user_id = #{userId} and source_role.created_by = #{userId} and target_role.created_by = #{userId} and fs.user_id = #{userId} and ts.user_id = #{userId}
